"use strict";parserFactory.register("novelcool.com",()=>new NovelcoolParser);class NovelcoolParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".chapter-item-list a")].map(this.linkToChapter).reverse()}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("span.chapter-item-headtitle").textContent}}findContent(e){return e.querySelector(".chapter-reading-section-list, .overflow-hidden")}extractTitleImpl(e){return e.querySelector("h1.bookinfo-title")}extractAuthor(e){return e.querySelector(".bookinfo-author a")?.textContent??null}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".chapter-end-mark, .chapter-section-report"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,".bookinfo-pic")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".bk-summary-txt")]}}